document.addEventListener("DOMContentLoaded", () => {
  "use strict";

  // 1. 终极性能与兼容优化：Intersection Observer 视频安全懒加载
  const lazyVideos = document.querySelectorAll('video.lazy-video');
  
  if ('IntersectionObserver' in window) {
    const videoObserver = new IntersectionObserver((entries, observer) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const video = entry.target;
          
          // 确保只加载一次
          if (video.dataset.src && !video.getAttribute('src')) {
            video.src = video.dataset.src;
            
            // 关键补丁：针对移动端和Safari，重新强制申明静音和内联播放
            video.setAttribute('playsinline', '');
            video.setAttribute('webkit-playsinline', '');
            video.setAttribute('muted', '');
            video.muted = true;
            video.autoplay = true;

            video.load();
            
            // 安全捕获 Play Promise 异常（防止低电量模式抛出未捕获错误）
            const playPromise = video.play();
            if (playPromise !== undefined) {
              playPromise.then(() => {
                video.classList.remove('lazy-video');
              }).catch(error => {
                console.log("Auto-play prevented by browser policy/low-power mode.", error);
              });
            }
            
            // 加载完成后取消监听
            observer.unobserve(video); 
          }
        }
      });
    }, { 
      // 提前 50% 的屏幕高度开始预加载，防止划到时黑屏
      rootMargin: "0px 0px 50% 0px",
      threshold: 0.1 
    });
    
    lazyVideos.forEach(video => {
      videoObserver.observe(video);
    });
  } else {
    // 兼容不支持 Observer 的旧版浏览器
    lazyVideos.forEach(video => {
      if (video.dataset.src) {
        video.src = video.dataset.src;
        video.load();
        video.play().catch(e => console.log(e));
      }
    });
  }

  // 2. 表单联动功能优化
  const colorData = {
    A: [['A1','1. White'],['A2','2. Beige'],['A3','3. Gray'],['A4','4. Dark Gray'],['A5','5. Brown'],['A6','6. Black']],
    B: [['B1','1. White'],['B2','2. Dark Gray'],['B3','3. Beige'],['B4','4. Dark Gray']],
    C: [['C1','1. Beige'],['C2','2. Brown'],['C3','3. Light Gray'],['C4','4. Dark Gray'],['C5','5. Black']],
    D: [['D1','1. White'],['D2','2. Yellow'],['D3','3. Dark Brown'],['D4','4. Light Gray'],['D5','5. Dark Gray'],['D6','6. Black Gray'],['D7','7. Black']],
    E: [['E1','1. White'],['E2','2. Beige'],['E3','3. Brown'],['E4','4. Light Gray'],['E5','5. Black']],
    F: [['F1','1. Light Gray'],['F2','2. Brown'],['F3','3. Black']]
  };
  
  const openness = document.getElementById('opennessType');
  const fabColor = document.getElementById('fabricColorChoice');
  const aluColor = document.getElementById('aluminiumColorChoice');
  
  if (openness && fabColor && aluColor) {
    openness.addEventListener('change', (e) => {
      const selectedSeries = e.target.value;
      aluColor.style.display = '';
      aluColor.required = true;
      
      // 清空并重置选项
      fabColor.innerHTML = '<option value="" disabled selected>Select Fabric Color</option>';
      
      if (colorData[selectedSeries]) {
        // 使用 DocumentFragment 提升渲染性能
        const fragment = document.createDocumentFragment();
        colorData[selectedSeries].forEach(([val, label]) => {
          const opt = document.createElement('option');
          opt.value = val; 
          opt.textContent = label;
          fragment.appendChild(opt);
        });
        fabColor.appendChild(fragment);
      }
    });
  }

  // 3. WhatsApp 报价发送功能 (防连点保护)
  const form = document.getElementById('budgetForm');
  let isSubmitting = false;

  if (form) {
    form.addEventListener('submit', (e) => {
      e.preventDefault();
      if (isSubmitting) return;

      const name = document.getElementById('qName').value.trim();
      const address = document.getElementById('qAddress').value.trim();
      const height = document.getElementById('qHeight').value;
      const length = document.getElementById('qLength').value;
      const opennessVal = openness ? openness.value : '';
      const fabColorVal = fabColor ? fabColor.value : '';
      const aluColorVal = aluColor ? aluColor.value : '';

      if (!name || !address) {
          alert("Please fill in your Name and Address.");
          return;
      }
      
      isSubmitting = true;
      const submitBtn = document.getElementById('sendWhatsApp');
      const originalText = submitBtn.innerText;
      submitBtn.innerText = "Redirecting...";
      
      // 3秒防抖恢复
      setTimeout(() => { 
        isSubmitting = false; 
        submitBtn.innerText = originalText;
      }, 3000); 

      const text = `Hi Lion Sin, I'd like a quote!%0A%0AName: ${encodeURIComponent(name)}%0AAddress: ${encodeURIComponent(address)}%0ABalcony Height: ${encodeURIComponent(height)}m%0ABalcony Length: ${encodeURIComponent(length)}m%0AOpenness: ${encodeURIComponent(opennessVal)}%0AFabric Color: ${encodeURIComponent(fabColorVal)}%0AAluminium Color: ${encodeURIComponent(aluColorVal)}`;
      
      window.open(`https://wa.me/6583417888?text=${text}`, '_blank');
    });
  }

  // 4. 图片点击放大 (Lightbox) 功能优化
  const lightbox = document.getElementById("imageLightbox");
  const lightboxImg = document.getElementById("lightboxImg");
  const captionText = document.getElementById("lightboxCaption");
  const closeBtn = document.querySelector(".close-lightbox");
  const zoomableImages = document.querySelectorAll('.zoomable');

  const closeLightbox = () => {
    if (lightbox) {
      lightbox.style.opacity = '0'; // 配合 CSS fadeIn 动画退出
      setTimeout(() => {
        lightbox.style.display = "none";
        lightbox.style.opacity = '';
      }, 300); // 对应 CSS 动画时长
    }
  };

  if (lightbox && zoomableImages.length > 0) {
    zoomableImages.forEach(img => {
      img.addEventListener('click', function() {
        lightbox.style.display = "block";
        lightboxImg.src = this.src;
        const textNode = this.nextElementSibling ? this.nextElementSibling.querySelector('h4') : null;
        captionText.innerHTML = textNode ? textNode.innerText : this.alt;
      });
    });

    if (closeBtn) closeBtn.addEventListener('click', closeLightbox);

    lightbox.addEventListener('click', (e) => {
      if (e.target === lightbox) {
        closeLightbox();
      }
    });
    
    document.addEventListener('keydown', (e) => {
      if (e.key === "Escape" && lightbox.style.display === "block") {
        closeLightbox();
      }
    });
  }
});
